mapper.select:
/* GoodsMapper.getAdminGoodsList: 관리자 상품 목록 조회 */ SELECT GB.GOODS_ID , GB.BRAND_NO , BB.BRAND_NM AS BRAND_NM , GB.ERP_STYLE_CD , GB.GOODS_NM , GB.GOODS_STAT_CD , FN_GET_CODE_NM('GOODS_STAT', GB.GOODS_STAT_CD) AS GOODS_STAT_NM , GB.GOODS_DIV_CD , FN_GET_CODE_NM('GOODS_DIV', GB.GOODS_DIV_CD) AS GOODS_DIV_NM , GB.SHOW_YN , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = GB.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH , GB.REG_DT , GB.UDT_DT FROM GOODS_BASE GB LEFT JOIN BRAND_BASE BB ON BB.BRAND_NO = GB.BRAND_NO WHERE 1 = 1
AND GB.GOODS_STAT_CD = #{goodsStatCd}
AND GB.GOODS_DIV_CD = #{goodsDivCd}
AND GB.GOODS_MERCH_ID = #{goodsMerchId}
AND GB.SHOW_YN = #{showYn}
AND GB.BRAND_NO = #{brandNo}
AND EXISTS ( SELECT 1 FROM CATEGORY_GOODS CG WHERE CG.GOODS_ID = GB.GOODS_ID AND CG.CATEGORY_ID = #{categoryId} )
AND GB.GOODS_ID LIKE CONCAT(#{searchValue}, '%')
AND GB.ERP_STYLE_CD LIKE CONCAT(#{searchValue}, '%')
AND MATCH(GB.GOODS_NM) AGAINST(#{searchKeyword} IN BOOLEAN MODE)
ORDER BY GB.REG_DT DESC LIMIT #{pageSize} OFFSET #{offset}

/* GoodsMapper.getAdminGoodsCount: 관리자 상품 목록 조회 수 */
SELECT COUNT(1)
  FROM GOODS_BASE GB
 WHERE 1 = 1

   AND GB.GOODS_STAT_CD = #{goodsStatCd}


   AND GB.GOODS_DIV_CD = #{goodsDivCd}


   AND GB.GOODS_MERCH_ID = #{goodsMerchId}


   AND GB.SHOW_YN = #{showYn}


   AND GB.BRAND_NO = #{brandNo}


   AND EXISTS (
       SELECT 1
         FROM CATEGORY_GOODS CG
        WHERE CG.GOODS_ID = GB.GOODS_ID
          AND CG.CATEGORY_ID = #{categoryId}
   )




   AND GB.GOODS_ID LIKE CONCAT(#{searchValue}, '%')


   AND GB.ERP_STYLE_CD LIKE CONCAT(#{searchValue}, '%')


   AND MATCH(GB.GOODS_NM) AGAINST(#{searchKeyword} IN BOOLEAN MODE)

mapper.sql:
/* GoodsMapper.adminOrderWhere: 관리자 주문 목록 공통 조회 조건 */
WHERE 1 = 1
  AND OD.ORD_DTL_STAT_CD != 'ORD_DTL_STAT_00'



   AND OD.ORD_NO = #{searchValue}


   AND OD.GOODS_ID LIKE CONCAT('%', #{searchValue}, '%')




   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}


   AND OB.ORDER_CONFIRM_DT >= #{startDateTime}
   AND OB.ORDER_CONFIRM_DT < #{endExclusiveDateTime}


   AND OD.ORD_DTL_STAT_CD = #{ordDtlStatCd}


   AND EXISTS (
       SELECT 1
         FROM ORDER_CHANGE_DETAIL OCD
        WHERE OCD.ORD_NO = OD.ORD_NO
          AND OCD.ORD_DTL_NO = OD.ORD_DTL_NO
          AND OCD.CHG_DTL_STAT_CD = #{chgDtlStatCd}
   )

/* GoodsMapper.adminOrderStartDeliveryWhere: 관리자 배송 시작 관리 공통 조회 조건 */
WHERE OD.ORD_DTL_STAT_CD = #{ordDtlStatCd}
  AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0

