mapper.select:
/* GoodsMapper.countAdminCategoryChildren: 관리자 카테고리 하위 건수 조회 */
SELECT COUNT(1)
  FROM CATEGORY
 WHERE PARENT_CATEGORY_ID = #{categoryId}

/* GoodsMapper.countAdminCategoryById: 관리자 카테고리 중복 건수 조회 */
SELECT COUNT(1)
  FROM CATEGORY
 WHERE CATEGORY_ID = #{categoryId}

/* GoodsMapper.countAdminCategoryGoods: 관리자 카테고리 상품 사용 건수 조회 */
SELECT COUNT(1)
  FROM CATEGORY_GOODS
 WHERE CATEGORY_ID = #{categoryId}

/* GoodsMapper.countShopWishList: 쇼핑몰 상품 위시리스트 등록 여부 건수 조회 */
SELECT COUNT(1)
  FROM WISH_LIST
 WHERE CUST_NO = #{custNo}
   AND GOODS_ID = #{goodsId}

/* GoodsMapper.countShopMypageOrderGroup: 쇼핑몰 마이페이지 주문내역 주문번호 건수 조회 */
SELECT COUNT(*)
  FROM ORDER_BASE OB
 WHERE OB.CUST_NO = #{custNo}
   AND OB.ORD_STAT_CD != 'ORD_STAT_00'
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}
   AND EXISTS (
       SELECT 1
         FROM ORDER_DETAIL OD
        WHERE OD.ORD_NO = OB.ORD_NO
          AND OD.ORD_DTL_STAT_CD NOT IN ('ORD_DTL_STAT_00', 'ORD_DTL_STAT_99')
   )

/* GoodsMapper.getShopMypageOrderGroupList: 쇼핑몰 마이페이지 주문내역 주문번호 목록 페이징 조회 */
SELECT OB.ORD_NO
     , DATE_FORMAT(COALESCE(OB.ORDER_DT, OB.REG_DT), '%Y-%m-%d %H:%i:%s') AS ORDER_DT
  FROM ORDER_BASE OB
 WHERE OB.CUST_NO = #{custNo}
   AND OB.ORD_STAT_CD != 'ORD_STAT_00'
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) >= #{startDateTime}
   AND COALESCE(OB.ORDER_DT, OB.REG_DT) < #{endExclusiveDateTime}
   AND EXISTS (
       SELECT 1
         FROM ORDER_DETAIL OD
        WHERE OD.ORD_NO = OB.ORD_NO
          AND OD.ORD_DTL_STAT_CD NOT IN ('ORD_DTL_STAT_00', 'ORD_DTL_STAT_99')
   )
 ORDER BY COALESCE(OB.ORDER_DT, OB.REG_DT) DESC, OB.ORD_NO DESC
 LIMIT #{pageSize} OFFSET #{offset}

/* GoodsMapper.getShopMypageOrderDetailList: 쇼핑몰 마이페이지 주문내역 주문상세 목록 조회 */ SELECT OD.ORD_NO , OD.ORD_DTL_NO , OD.ORD_DTL_STAT_CD , FN_GET_CODE_NM('ORD_DTL_STAT', OD.ORD_DTL_STAT_CD) AS ORD_DTL_STAT_NM , CASE WHEN OD.ORD_DTL_STAT_CD = 'ORD_DTL_STAT_06' AND COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) > 0 AND NOT EXISTS ( SELECT 1 FROM ORDER_CHANGE_DETAIL OCD JOIN ORDER_CHANGE_BASE OCB ON OCB.CLM_NO = OCD.CLM_NO AND OCB.ORD_NO = OCD.ORD_NO WHERE OCD.ORD_NO = OD.ORD_NO AND OCD.ORD_DTL_NO = OD.ORD_DTL_NO AND COALESCE(OCB.CHG_STAT_CD, '') != 'CHG_STAT_02' AND COALESCE(OCD.CHG_DTL_STAT_CD, '') NOT IN ('CHG_DTL_STAT_02', 'CHG_DTL_STAT_14', 'CHG_DTL_STAT_33') ) THEN TRUE ELSE FALSE END AS RETURN_APPLYABLE_YN , OD.GOODS_ID , GB.GOODS_NM , OD.SIZE_ID , OD.ORD_QTY , COALESCE(OD.RMN_QTY, OD.ORD_QTY, 0) AS CANCELABLE_QTY , OD.SUPPLY_AMT , OD.SALE_AMT , OD.ADD_AMT , COALESCE(OD.GOODS_CPN_DC_AMT, 0) AS GOODS_COUPON_DISCOUNT_AMT , COALESCE(OD.CART_CPN_DC_AMT, 0) AS CART_COUPON_DISCOUNT_AMT , COALESCE(OD.POINT_USE_AMT, 0) AS POINT_USE_AMT , OD.GOODS_CPN_NO , OD.CART_CPN_NO , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = OD.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH FROM ORDER_DETAIL OD JOIN ORDER_BASE OB ON OB.ORD_NO = OD.ORD_NO LEFT JOIN GOODS_BASE GB ON GB.GOODS_ID = OD.GOODS_ID WHERE OD.ORD_NO IN
#{ordNo}
AND OD.ORD_DTL_STAT_CD != 'ORD_DTL_STAT_00' ORDER BY COALESCE(OB.ORDER_DT, OB.REG_DT) DESC, OD.ORD_NO DESC, OD.ORD_DTL_NO ASC

/* GoodsMapper.countShopMypageCouponUnavailableGoods: 쇼핑몰 마이페이지 쿠폰 사용 불가 상품 전체 건수 조회 */ SELECT COUNT(*) FROM ( SELECT DISTINCT GB.GOODS_ID FROM GOODS_BASE GB
WHERE GB.GOODS_ID IN
#{targetValue}
WHERE CAST(GB.BRAND_NO AS CHAR) IN
#{targetValue}
JOIN CATEGORY_GOODS CG ON CG.GOODS_ID = GB.GOODS_ID WHERE CG.CATEGORY_ID IN
#{targetValue}
JOIN EXHIBITION_TAB_GOODS ETG ON ETG.GOODS_ID = GB.GOODS_ID AND ETG.VIEW_YN = 'Y' WHERE CAST(ETG.EXHIBITION_TAB_NO AS CHAR) IN
#{targetValue}
WHERE 1 = 0
AND GB.SHOW_YN = 'Y' AND GB.GOODS_STAT_CD = 'GOODS_STAT_02' ) TEMP

/* GoodsMapper.getShopMypageCouponUnavailableGoodsList: 쇼핑몰 마이페이지 쿠폰 사용 불가 상품 목록 조회 */ SELECT DISTINCT GB.GOODS_ID , GB.GOODS_NM FROM GOODS_BASE GB
WHERE GB.GOODS_ID IN
#{targetValue}
WHERE CAST(GB.BRAND_NO AS CHAR) IN
#{targetValue}
JOIN CATEGORY_GOODS CG ON CG.GOODS_ID = GB.GOODS_ID WHERE CG.CATEGORY_ID IN
#{targetValue}
JOIN EXHIBITION_TAB_GOODS ETG ON ETG.GOODS_ID = GB.GOODS_ID AND ETG.VIEW_YN = 'Y' WHERE CAST(ETG.EXHIBITION_TAB_NO AS CHAR) IN
#{targetValue}
WHERE 1 = 0
AND GB.SHOW_YN = 'Y' AND GB.GOODS_STAT_CD = 'GOODS_STAT_02' ORDER BY GB.GOODS_ID ASC LIMIT #{limit}

/* GoodsMapper.getShopOrderCartItemList: 쇼핑몰 주문서 대상 장바구니 목록 조회 */ SELECT C.CART_ID , C.CART_GB_CD , C.CUST_NO , C.GOODS_ID , GB.BRAND_NO , BB.BRAND_NM , GB.GOODS_NM , C.SIZE_ID , C.QTY , GB.SUPPLY_AMT , GB.SALE_AMT , GS.ADD_AMT , C.EXHIBITION_NO , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = C.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH FROM CART C JOIN GOODS_BASE GB ON GB.GOODS_ID = C.GOODS_ID JOIN GOODS_SIZE GS ON GS.GOODS_ID = C.GOODS_ID AND GS.SIZE_ID = C.SIZE_ID LEFT JOIN BRAND_BASE BB ON BB.BRAND_NO = GB.BRAND_NO WHERE C.CUST_NO = #{custNo} AND C.CART_ID IN
#{cartId}
AND C.CART_GB_CD IN ('C', 'O') ORDER BY C.REG_DT DESC, C.CART_ID DESC

/* GoodsMapper.countShopOrderAddressName: 쇼핑몰 주문서 배송지 별칭 중복 건수 조회 */
SELECT COUNT(1)
  FROM CUSTOMER_ADDRESS
 WHERE CUST_NO = #{custNo}
   AND ADDRESS_NM = #{addressNm}

/* GoodsMapper.countShopOrderAddress: 쇼핑몰 주문서 배송지 단건 존재 여부 조회 */
SELECT COUNT(1)
  FROM CUSTOMER_ADDRESS
 WHERE CUST_NO = #{custNo}
   AND ADDRESS_NM = #{addressNm}

