 WHERE CUST_NO = #{custNo}
   AND CUST_CPN_NO IN

	#{custCpnNo}

/* GoodsMapper.restoreShopCustomerCouponUse: 주문번호 기준 고객쿠폰 사용 처리 원복
   - ORDER_DETAIL의 GOODS_CPN_NO, CART_CPN_NO와 ORDER_BASE의 DELV_CPN_NO를 읽어 해당 CUST_CPN_NO만 원복
   - CUSTOMER_COUPON.ORD_NO = #{ordNo} 조건으로 재사용된 쿠폰(다른 주문에 이미 사용된 경우)은 원복 제외 */
UPDATE CUSTOMER_COUPON
   SET CPN_USE_YN = 'N'
     , ORD_NO = NULL
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CUST_NO = #{custNo}
   AND ORD_NO = #{ordNo}
   AND CUST_CPN_NO IN (
       SELECT cpn_no
         FROM (
              SELECT GOODS_CPN_NO AS cpn_no
                FROM ORDER_DETAIL
               WHERE ORD_NO = #{ordNo}
                 AND GOODS_CPN_NO IS NOT NULL
               UNION
              SELECT CART_CPN_NO AS cpn_no
                FROM ORDER_DETAIL
               WHERE ORD_NO = #{ordNo}
                 AND CART_CPN_NO IS NOT NULL
               UNION
              SELECT DELV_CPN_NO AS cpn_no
                FROM ORDER_BASE
               WHERE ORD_NO = #{ordNo}
                 AND DELV_CPN_NO IS NOT NULL
         ) AS cpn_list
   )

/* GoodsMapper.restoreShopCustomerCouponUseByCustCpnNo: 배송비 고객쿠폰 1건 사용 처리 원복 */
