/* GoodsMapper.updateShopCustomerPointUseAmt: 포인트 마스터 사용 금액 차감 */
UPDATE CUSTOMER_POINT_BASE
   SET USE_AMT = USE_AMT + #{useAmt}
     , RMN_AMT = RMN_AMT - #{useAmt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PNT_NO = #{pntNo}

/* GoodsMapper.restoreShopCustomerPointUseAmt: 포인트 마스터 사용 금액 복구 */
UPDATE CUSTOMER_POINT_BASE
   SET USE_AMT = USE_AMT - #{restoreAmt}
     , RMN_AMT = RMN_AMT + #{restoreAmt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE PNT_NO = #{pntNo}

