/* GoodsMapper.countAdminGoodsDesc: 관리자 상품 상세 설명 건수 조회 */
SELECT COUNT(1)
  FROM GOODS_DESC
 WHERE GOODS_ID = #{goodsId}
   AND DEVICE_GB_CD = #{deviceGbCd}

mapper.insert:
/* GoodsMapper.insertAdminGoodsDesc: 관리자 상품 상세 설명 등록 */
INSERT INTO GOODS_DESC (
       GOODS_ID
     , DEVICE_GB_CD
     , GOODS_DESC
     , REG_NO
     , UDT_NO
) VALUES (
       #{goodsId}
     , #{deviceGbCd}
     , #{goodsDesc}
     , #{regNo}
     , #{udtNo}
)

mapper.update:
/* GoodsMapper.updateAdminGoodsDesc: 관리자 상품 상세 설명 수정 */
UPDATE GOODS_DESC
   SET GOODS_DESC = #{goodsDesc}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE GOODS_ID = #{goodsId}
   AND DEVICE_GB_CD = #{deviceGbCd}

mapper.select:
/* GoodsMapper.countShopMypageCancelHistory: 쇼핑몰 마이페이지 취소내역 클레임 전체 건수 조회 */
SELECT COUNT(DISTINCT OCB.CLM_NO)
  FROM ORDER_CHANGE_BASE OCB
 WHERE OCB.REG_NO = #{custNo}
   AND OCB.CHG_GB_CD = 'C'
   AND DATE(OCB.CHG_DT) >= #{startDate}
   AND DATE(OCB.CHG_DT) <= #{endDate}

/* GoodsMapper.getShopMypageCancelHistoryList: 쇼핑몰 마이페이지 취소내역 클레임 목록 페이징 조회 */
SELECT OCB.CLM_NO
     , OCB.ORD_NO
     , DATE_FORMAT(OCB.CHG_DT, '%Y-%m-%d %H:%i:%s') AS CHG_DT
     , OCB.CHG_STAT_CD
     , FN_GET_CODE_NM('CHG_STAT', OCB.CHG_STAT_CD) AS CHG_STAT_NM
     , COALESCE(OCB.PAY_DELV_AMT, 0) AS PAY_DELV_AMT
     , COALESCE(P.CNL_AMT, 0) AS REFUNDED_CASH_AMT
  FROM ORDER_CHANGE_BASE OCB
  LEFT JOIN PAYMENT P ON P.CLM_NO = OCB.CLM_NO
 WHERE OCB.REG_NO = #{custNo}
   AND OCB.CHG_GB_CD = 'C'
   AND DATE(OCB.CHG_DT) >= #{startDate}
   AND DATE(OCB.CHG_DT) <= #{endDate}
 ORDER BY OCB.CHG_DT DESC, OCB.CLM_NO DESC
 LIMIT #{pageSize} OFFSET #{offset}

/* GoodsMapper.getShopMypageCancelHistoryDetailList: 쇼핑몰 마이페이지 취소내역 상품 상세 목록 조회 */ SELECT OCD.CLM_NO , OCD.ORD_DTL_NO , OCD.GOODS_ID , GB.GOODS_NM , OCD.SIZE_ID , OCD.QTY , COALESCE(OD.SALE_AMT, 0) AS SALE_AMT , COALESCE(OCD.ADD_AMT, 0) AS ADD_AMT , OCD.CHG_REASON_CD , FN_GET_CODE_NM('CHG_REASON', OCD.CHG_REASON_CD) AS CHG_REASON_NM , OCD.CHG_REASON_DTL , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = OCD.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_PATH , ( SELECT GI.IMG_PATH FROM GOODS_IMG GI WHERE GI.GOODS_ID = OCD.GOODS_ID ORDER BY GI.DISP_ORD ASC, GI.IMG_NO ASC LIMIT 1 ) AS IMG_URL FROM ORDER_CHANGE_DETAIL OCD JOIN GOODS_BASE GB ON GB.GOODS_ID = OCD.GOODS_ID LEFT JOIN ORDER_DETAIL OD ON OD.ORD_NO = OCD.ORD_NO AND OD.ORD_DTL_NO = OCD.ORD_DTL_NO WHERE OCD.CLM_NO IN
#{clmNo}
ORDER BY OCD.CLM_NO, OCD.ORD_DTL_NO

/* GoodsMapper.getShopMypagePointItemCount: 마이페이지 포인트 적립/차감 내역 전체 건수 조회 */
SELECT COUNT(*)
  FROM CUSTOMER_POINT_DETAIL CPD
 INNER JOIN CUSTOMER_POINT_BASE CPB ON CPB.PNT_NO = CPD.PNT_NO
 WHERE CPB.CUST_NO = #{custNo}

/* GoodsMapper.getOrderCustNo: 주문번호로 고객번호 조회 */
SELECT CUST_NO
  FROM ORDER_BASE
 WHERE ORD_NO = #{ordNo}
 LIMIT 1
